CREATE TABLE "public"."knowledge_extraction" (

            "extraction_id"   int4                                        NOT NULL GENERATED BY DEFAULT AS IDENTITY (
                INCREMENT 1
MINVALUE  1
MAXVALUE 2147483647
START 1
CACHE 1
),
        "job_name" varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
        "space_id" int4                                        NOT NULL DEFAULT 0,
        "space_name" varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
        "tag_names" varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
        "edge_names" varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
        "type"          smallint                                    NOT NULL  DEFAULT 0,
        "deleted"       bool                                        NOT NULL DEFAULT false,
        "create_by"     int4                                        NOT NULL DEFAULT 1,
        "update_by"     int4                                        NOT NULL DEFAULT 1,
        "create_time"   timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP,
        "update_time"   timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP


);


ALTER TABLE "public"."knowledge_extraction"
    OWNER TO "postgres";


COMMENT
ON COLUMN "public"."knowledge_extraction"."extraction_id" IS '知识抽取ID';

COMMENT
ON COLUMN "public"."knowledge_extraction"."job_name" IS '任务名称';

COMMENT
ON COLUMN "public"."knowledge_extraction"."space_id" IS '图空间ID';

COMMENT
ON COLUMN "public"."knowledge_extraction"."space_name" IS '图空间名称';

COMMENT
ON COLUMN "public"."knowledge_extraction"."tag_names" IS '本体名称,以,分割';

COMMENT
ON COLUMN "public"."knowledge_extraction"."edge_names" IS '关系名称,以,分割';

COMMENT
ON COLUMN "public"."knowledge_graph_visual_manage"."deleted" IS '是否删除 false 否 true 删除';

COMMENT
ON COLUMN "public"."knowledge_extraction"."create_time" IS '创建时间';

COMMENT
ON COLUMN "public"."knowledge_extraction"."create_by" IS '创建人ID';

COMMENT
ON COLUMN "public"."knowledge_extraction"."update_time" IS '更新时间';

COMMENT
ON COLUMN "public"."knowledge_extraction"."update_by" IS '更新人ID';

COMMENT
ON COLUMN "public"."knowledge_extraction"."type" IS '0 实体类型任务，1文档类型任务';



