         "file_path"     varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
         "file_format"   varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
         "analysis"      smallint                                    NOT NULL DEFAULT 0,
         "document_status"   int4                                    NOT NULL DEFAULT 0,
