ON COLUMN "public"."knowledge_document_information"."document_status" IS '抽取状态';

COMMENT
ON COLUMN "public"."knowledge_document_information"."chunk_size" IS 'chunk总数量';

COMMENT
ON COLUMN "public"."knowledge_document_information"."job_id" IS '解析文件任务id';

COMMENT
ON COLUMN "public"."knowledge_document_information"."deleted" IS '是否删除 false 否 true 删除';

