            "verification_id"   int4                                        NOT NULL GENERATED BY DEFAULT AS IDENTITY (
                INCREMENT 1
MINVALUE  1
MAXVALUE 2147483647
START 1
CACHE 1
),
        "document_id"           int4                                        NOT NULL DEFAULT 0,
        "chunk_id"              int4                                        NOT NULL DEFAULT 0,
        "subject"               varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
        "subject_tag_name"      varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
        "edge_type"             varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
        "object"                varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
        "object_tag_name"       varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
        "type"                  smallint                                    NOT NULL  DEFAULT 0,
        "verification_status"   smallint                                    NOT NULL  DEFAULT 0,
        "property_type"         varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
        "deleted"               bool                                        NOT NULL DEFAULT false,
        "create_by"             int4                                        NOT NULL DEFAULT 1,
        "update_by"             int4                                        NOT NULL DEFAULT 1,
        "create_time"           timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP,
        "update_time"           timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP

);


ALTER TABLE "public"."knowledge_document_verification"
    OWNER TO "postgres";

COMMENT
ON COLUMN "public"."knowledge_document_verification"."verification_id" IS '文档校验 id';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."document_id" IS '所属文档ID';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."chunk_id" IS 'chunk id';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."subject" IS '主体类型';

COMMENT
ON COLUMN "public"."knowledge_document_verification".subject_tag_name IS '主体名称';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."edge_type" IS '关系/属性';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."object" IS '主体类型';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."type" IS '关系属性，0表示关系，1表述属性';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."verification_status" IS '校验状态，0初始状态，1表示已校验,2已入图';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."property_type" IS '解析文件任务id';


COMMENT
ON COLUMN "public"."knowledge_document_verification"."deleted" IS '是否删除 false 否 true 删除';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."create_by" IS '创建人';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."update_by" IS '更新人';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."create_time" IS '创建时间';

COMMENT
ON COLUMN "public"."knowledge_document_verification"."update_time" IS '更新时间';


